package com.dissertation.userservice.controller;

import com.dissertation.userservice.dto.AuthRequest;
import com.dissertation.userservice.dto.AuthResponse;
import com.dissertation.userservice.dto.RegisterRequest;
import com.dissertation.userservice.dto.UserResponse;
import com.dissertation.userservice.service.AuthService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.authentication.BadCredentialsException;
import org.springframework.security.core.AuthenticationException;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/auth")
@RequiredArgsConstructor
@CrossOrigin(origins = "*", maxAge = 3600)
@Slf4j
public class AuthController {

    private final AuthService authService;

    @PostMapping("/register")
    public ResponseEntity<AuthResponse> register(@Valid @RequestBody RegisterRequest request, HttpServletRequest httpRequest) {
        log.info("=== Register Request Received ===");
        log.info("Method: {}", httpRequest.getMethod());
        log.info("Request URI: {}", httpRequest.getRequestURI());
        return ResponseEntity.ok(authService.register(request));
    }

    @PostMapping("/login")
    public ResponseEntity<?> login(@Valid @RequestBody AuthRequest request) {
        try {
            AuthResponse response = authService.authenticate(request);
            return ResponseEntity.ok(response);
        } catch (BadCredentialsException e) {
            log.warn("Login failed for username: {} - Bad credentials", request.getUsername());
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED)
                    .body("{\"error\":\"Unauthorized\",\"message\":\"Invalid username or password\"}");
        } catch (AuthenticationException e) {
            log.warn("Login failed for username: {} - Authentication exception: {}", request.getUsername(), e.getMessage());
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED)
                    .body("{\"error\":\"Unauthorized\",\"message\":\"" + e.getMessage() + "\"}");
        } catch (Exception e) {
            log.error("Login failed for username: {} - Unexpected error", request.getUsername(), e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body("{\"error\":\"Internal Server Error\",\"message\":\"An unexpected error occurred\"}");
        }
    }

    @GetMapping("/user/{username}")
    public ResponseEntity<UserResponse> getUser(@PathVariable String username) {
        return ResponseEntity.ok(authService.getUserByUsername(username));
    }

    @GetMapping("/health")
    public ResponseEntity<String> health() {
        return ResponseEntity.ok("User Service is running");
    }
}

package com.dissertation.userservice.dto;

import jakarta.validation.constraints.Email;
import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.Size;
import lombok.Data;

@Data
public class RegisterRequest {
    @NotBlank(message = "Username is required")
    @Size(min = 3, max = 20, message = "Username must be between 3 and 20 characters")
    private String username;

    @NotBlank(message = "Email is required")
    @Email(message = "Invalid email format")
    private String email;

    @NotBlank(message = "Password is required")
    @Size(min = 6, message = "Password must be at least 6 characters")
    private String password;

    private String role = "USER";
}

public class MicroservicesIntegrationTest {
    private static final String BASE_URL = "http://localhost:8080";

    @Test(priority = 12, description = "user registration")
    public void testUserRegistrationContract() {
        Map<String, Object> wrongBody = new HashMap<>();
        wrongBody.put("userName", "contractuser");  
        wrongBody.put("mail", "contractuser@example.com");  
        wrongBody.put("password", "password123");
        wrongBody.put("role", "USER");

        Response response = RestAssured.given()
                .baseUri(BASE_URL)
                .contentType(ContentType.JSON)
                .body(wrongBody)
                .when()
                .post("/api/auth/register")
                .then()
                .extract()
                .response();

        Reporter.log("Response Body: " + response.getBody().asString(), true);

        Assert.assertEquals(response.getStatusCode(), 200,
                "it should return 200. " +
                        "Actual status: " + response.getStatusCode() + ". Response: " + response.getBody().asString());
    }
}
